def f_beta(precision: float, recall: float, beta: float) -> float:
    if precision + recall == 0:
        return 0.0
    b2 = beta ** 2
    return (1 + b2) * precision * recall / (b2 * precision + recall)

p, r = 0.6, 0.9  # High recall, lower precision
print(f"F2  (recall-heavy): {f_beta(p, r, 2.0):.3f}")   # 0.818
print(f"F1  (balanced):     {f_beta(p, r, 1.0):.3f}")   # 0.720
print(f"F.5 (precision-heavy): {f_beta(p, r, 0.5):.3f}") # 0.625

from sklearn.metrics import (
    accuracy_score, precision_score, recall_score,
    f1_score, classification_report
)

def full_eval_report(y_true, y_pred, class_names):
    return {
        "accuracy":    accuracy_score(y_true, y_pred),
        "f1_weighted": f1_score(y_true, y_pred, average="weighted", zero_division=0),
        "f1_macro":    f1_score(y_true, y_pred, average="macro", zero_division=0),
        "per_class":   classification_report(
                           y_true, y_pred,
                           target_names=class_names,
                           output_dict=True),
    }

