import json, datetime
from pathlib import Path

class MetricsTracker:
    def __init__(self, log_path: str):
        self.log_path = Path(log_path)

    def record(self, run_id: str, prompt_version: str, metrics: dict):
        entry = {
            "ts": datetime.datetime.utcnow().isoformat(),
            "run_id": run_id,
            "prompt_version": prompt_version,
            **metrics,
        }
        with self.log_path.open("a") as f:
            f.write(json.dumps(entry) + "\n")

    def load_history(self) -> list[dict]:
        if not self.log_path.exists():
            return []
        return [json.loads(line) for line in self.log_path.read_text().splitlines()]

    def regression_check(self, metric: str, threshold_drop: float = 0.05) -> bool:
        """Return True if latest run dropped more than threshold vs prior run."""
        history = self.load_history()
        if len(history) < 2:
            return False
        latest = history[-1][metric]
        prior  = history[-2][metric]
        return (prior - latest) > threshold_drop

tracker = MetricsTracker("eval_history.jsonl")
tracker.record("run_001", "v3", {"accuracy": 0.87, "f1_macro": 0.82})
tracker.record("run_002", "v4", {"accuracy": 0.85, "f1_macro": 0.79})
if tracker.regression_check("f1_macro"):
